/* ─── Landing Page ─────────────────────────────────────────────────────────── */

.landing-shell {
  position: relative;
  min-height: 100svh;
  overflow-x: clip;
  color: #1f1b16;
  background:
    radial-gradient(circle at 8% 12%, rgba(255, 160, 96, 0.42), transparent 34%),
    radial-gradient(circle at 92% 88%, rgba(222, 121, 75, 0.3), transparent 30%),
    linear-gradient(136deg, #f8f4ed 0%, #efe1d0 42%, #f6eee4 100%);
}

.landing-grid {
  position: absolute;
  inset: 0;
  z-index: 0;
  opacity: 0.18;
  background-image:
    linear-gradient(rgba(86, 64, 47, 0.1) 1px, transparent 1px),
    linear-gradient(90deg, rgba(86, 64, 47, 0.1) 1px, transparent 1px);
  background-size: 30px 30px;
  mask-image: radial-gradient(circle at 40% 20%, #000 12%, transparent 72%);
  pointer-events: none;
}

.landing-spot {
  position: absolute;
  border-radius: 999px;
  filter: blur(80px);
  pointer-events: none;
  z-index: 0;
}

.landing-spot-left {
  width: 260px;
  height: 260px;
  left: 4%;
  top: 10%;
  background: rgba(255, 123, 55, 0.4);
}

.landing-spot-right {
  width: 280px;
  height: 280px;
  right: 6%;
  bottom: 12%;
  background: rgba(211, 106, 62, 0.32);
}

.landing-header,
.landing-hero,
.landing-section,
.landing-cta,
.landing-footer {
  position: relative;
  z-index: 1;
}

.landing-header {
  width: min(1120px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 1.25rem 0 0.5rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.landing-logo {
  font-size: 1.55rem;
  font-weight: 700;
  color: #c24f1f;
  text-decoration: none;
}

.landing-nav {
  display: flex;
  align-items: center;
  gap: 0.85rem;
  flex-wrap: wrap;
  justify-content: flex-end;
}

.landing-nav-link {
  color: #5b4f42;
  text-decoration: none;
  font-size: 0.9rem;
  font-weight: 500;
  transition: color 160ms ease;
}

.landing-nav-link:hover {
  color: #c24f1f;
}

.landing-hero {
  width: min(1120px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 3.5rem 0 4rem;
  text-align: center;
}

.landing-kicker {
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: #7a6556;
  font-size: 0.72rem;
  font-weight: 700;
}

.landing-title {
  margin-top: 0.75rem;
  font-size: clamp(2.2rem, 5vw, 3.6rem);
  line-height: 1.08;
  font-weight: 700;
  color: #2d2118;
  max-width: 18ch;
  margin-inline: auto;
}

.landing-lead {
  margin: 1.15rem auto 0;
  max-width: 62ch;
  color: #5b4f42;
  line-height: 1.65;
  font-size: 1.05rem;
}

.landing-hero-actions {
  margin-top: 1.75rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.85rem;
  justify-content: center;
}

.landing-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 12px;
  padding: 0.8rem 1.25rem;
  font-size: 0.95rem;
  font-weight: 700;
  text-decoration: none;
  transition: transform 160ms ease, filter 160ms ease, box-shadow 160ms ease;
}

.landing-btn:hover {
  transform: translateY(-1px);
}

.landing-btn-sm {
  padding: 0.55rem 0.95rem;
  font-size: 0.85rem;
}

.landing-btn-primary {
  background: linear-gradient(180deg, #ff7f55 0%, #f47144 100%);
  color: #4a1500;
  border: 1px solid rgba(169, 72, 34, 0.35);
  box-shadow: 0 10px 24px rgba(244, 113, 68, 0.28);
}

.landing-btn-primary:hover {
  filter: brightness(1.04);
}

.landing-btn-secondary {
  background: rgba(255, 252, 246, 0.85);
  color: #4a3428;
  border: 1px solid rgba(130, 90, 64, 0.25);
}

.landing-btn-secondary:hover {
  background: #fffdf8;
}

.landing-btn-ghost {
  background: rgba(255, 255, 255, 0.08);
  color: #f7f0e7;
  border: 1px solid rgba(255, 255, 255, 0.18);
}

.landing-hero-stats {
  margin-top: 2.5rem;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.85rem;
  max-width: 720px;
  margin-inline: auto;
}

.landing-stat {
  border-radius: 16px;
  border: 1px solid rgba(197, 151, 119, 0.28);
  background: rgba(255, 252, 246, 0.72);
  padding: 1rem 0.75rem;
}

.landing-stat-value {
  display: block;
  font-size: 1.15rem;
  font-weight: 700;
  color: #c24f1f;
}

.landing-stat-label {
  display: block;
  margin-top: 0.25rem;
  font-size: 0.78rem;
  color: #7a6556;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.landing-section {
  width: min(1120px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 1rem 0 3.5rem;
}

.landing-section-head {
  text-align: center;
  max-width: 58ch;
  margin: 0 auto 2rem;
}

.landing-section-title {
  margin-top: 0.55rem;
  font-size: clamp(1.7rem, 3.5vw, 2.4rem);
  line-height: 1.15;
  font-weight: 700;
  color: #2d2118;
}

.landing-section-copy {
  margin-top: 0.85rem;
  color: #5b4f42;
  line-height: 1.6;
}

.landing-problem-grid,
.landing-feature-grid,
.landing-step-grid {
  display: grid;
  gap: 1rem;
}

.landing-problem-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.landing-feature-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.landing-step-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.landing-problem-card,
.landing-feature-card,
.landing-step-card {
  border-radius: 18px;
  padding: 1.35rem;
}

.landing-problem-card,
.landing-step-card {
  border: 1px solid rgba(197, 151, 119, 0.28);
  background: rgba(255, 252, 246, 0.78);
}

.landing-feature-card {
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: linear-gradient(145deg, rgba(28, 27, 29, 0.94), rgba(20, 20, 22, 0.98));
  color: #e5e1e4;
}

.landing-card-icon {
  font-size: 1.6rem;
  color: #e85d24;
}

.landing-feature-icon {
  font-size: 1.6rem;
  color: #ffb59d;
}

.landing-card-title {
  margin-top: 0.7rem;
  font-size: 1.1rem;
  font-weight: 700;
  line-height: 1.25;
}

.landing-card-copy {
  margin-top: 0.55rem;
  line-height: 1.55;
  font-size: 0.94rem;
}

.landing-problem-card .landing-card-copy,
.landing-step-card .landing-card-copy {
  color: #5b4f42;
}

.landing-feature-card .landing-card-copy {
  color: #c8c6c9;
}

.landing-step-number {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 2.2rem;
  height: 2.2rem;
  border-radius: 999px;
  background: rgba(244, 113, 68, 0.14);
  color: #c24f1f;
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.06em;
}

.landing-cta {
  width: min(1120px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 0 0 4rem;
}

.landing-cta-card {
  border-radius: 24px;
  padding: 2.25rem 1.5rem;
  text-align: center;
  background: linear-gradient(135deg, #1f1f23 0%, #141416 100%);
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow: 0 24px 48px rgba(20, 12, 8, 0.22);
}

.landing-cta-title {
  font-size: clamp(1.6rem, 3vw, 2.2rem);
  line-height: 1.15;
  color: #f3f0f2;
}

.landing-cta-copy {
  margin: 0.85rem auto 0;
  max-width: 48ch;
  color: #c8c6c9;
  line-height: 1.6;
}

.landing-footer {
  width: min(1120px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 0 0 2rem;
  text-align: center;
}

.landing-footer-brand {
  font-weight: 700;
  color: #c24f1f;
}

.landing-footer-copy {
  margin-top: 0.35rem;
  font-size: 0.88rem;
  color: #7a6556;
}

@media (max-width: 900px) {
  .landing-problem-grid,
  .landing-step-grid {
    grid-template-columns: 1fr;
  }

  .landing-feature-grid {
    grid-template-columns: 1fr;
  }

  .landing-hero-stats {
    grid-template-columns: 1fr;
  }

  .landing-nav a:not(.landing-btn) {
    display: none;
  }
}

@media (prefers-color-scheme: dark) {
  .landing-shell {
    color: #f7f0e7;
    background:
      radial-gradient(circle at 8% 12%, rgba(255, 143, 94, 0.28), transparent 34%),
      radial-gradient(circle at 92% 88%, rgba(255, 117, 71, 0.2), transparent 30%),
      linear-gradient(136deg, #1f1911 0%, #23190f 44%, #1c150e 100%);
  }

  .landing-title,
  .landing-section-title {
    color: #f7f0e7;
  }

  .landing-lead,
  .landing-section-copy,
  .landing-problem-card .landing-card-copy,
  .landing-step-card .landing-card-copy,
  .landing-nav-link,
  .landing-footer-copy {
    color: #c5b19a;
  }

  .landing-kicker {
    color: #a78b82;
  }

  .landing-stat,
  .landing-problem-card,
  .landing-step-card {
    background: rgba(40, 31, 22, 0.82);
    border-color: rgba(255, 174, 130, 0.18);
  }

  .landing-btn-secondary {
    background: rgba(40, 31, 22, 0.82);
    color: #ecd7c3;
    border-color: rgba(255, 173, 134, 0.22);
  }
}

/* ─── Dashboard Styles ────────────────────────────────────────────────────── */
